def solve(nums):
    n = len(nums)
    best = 0
    for skip in range(n):
        run = 0
        cur = 0
        for i in range(n):
            if i == skip:
                continue
            if nums[i] == 1:
                cur += 1
                if cur > run:
                    run = cur
            else:
                cur = 0
        if run > best:
            best = run
    return best


class Solution:
    def longestSubarray(self, nums):
        return solve(nums)

